1	// US-043 backend probe: signs up a fresh creator, then queries
2	// `list_my_applications` via PostgREST with the resulting Marketify JWT.
3	// Run mode is selected via argv[2]:
4	//
5	//   signup   — POST auth-signup-creator, print { user_id, token } and exit 0.
6	//              Used to bootstrap a verification fixture; the caller is then
7	//              responsible for inserting applications for `user_id` (via MCP
8	//              execute_sql with service_role) before running mode `query`.
9	//
10	//   query    — POST /rest/v1/rpc/list_my_applications with the JWT supplied
11	//              in MARKETIFY_PROBE_JWT env var. Prints the rows and asserts
12	//              there is at least one row in each of the 4 segment buckets
13	//              (pending / approved / rejected / cancelled). Exit 0 on full
14	//              coverage, exit 2 otherwise.
15	//
16	// Usage:
17	//   bun run scripts/test/probe-us043-list-apps.ts signup
18	//   MARKETIFY_PROBE_JWT=<jwt> bun run scripts/test/probe-us043-list-apps.ts query
19	//
20	// Why this exists: the in-app DevRolePicker uses a literal `dev-creator-token`
21	// string that PostgREST rejects with PGRST301. Only a JWT minted by
22	// `auth-signup-creator` (or `auth-signin-*` once it lands) is accepted. The
23	// SQL-level verification of the RPC body was completed in the original US-043
24	// commit — this probe closes the loop end-to-end through the PostgREST gateway
25	// without burning the DB-vs-PostgREST distinction.
26	
27	const supabaseUrl = process.env.SUPABASE_URL;
28	const anonKey = process.env.SUPABASE_ANON_KEY;
29	if (!supabaseUrl || !anonKey) {
30	  console.error("SUPABASE_URL and SUPABASE_ANON_KEY are required in .env");
31	  process.exit(1);
32	}
33	
34	const mode = process.argv[2];
35	if (mode !== "signup" && mode !== "query") {
36	  console.error("usage: bun run scripts/test/probe-us043-list-apps.ts <signup|query>");
37	  process.exit(1);
38	}
39	
40	if (mode === "signup") {
41	  const unique = Date.now();
42	  const res = await fetch(`${supabaseUrl}/functions/v1/auth-signup-creator`, {
43	    method: "POST",
44	    headers: {
45	      "Content-Type": "application/json",
46	      Authorization: `Bearer ${anonKey}`,
47	      apikey: anonKey,
48	    },
49	    body: JSON.stringify({
50	      username: `us043_probe_${unique}`,
51	      tiktok_handle: `us043_probe_${unique}`,
52	    }),
53	  });
54	  const body = (await res.json().catch(() => null)) as
55	    | { token?: string; user_id?: string }
56	    | null;
57	  console.log("[signup]", res.status);
58	  if (res.status !== 200 || !body?.token || !body?.user_id) {
59	    console.error("[signup] unexpected", body);
60	    process.exit(1);
61	  }
62	  console.log(JSON.stringify({ user_id: body.user_id, token: body.token }));
63	  process.exit(0);
64	}
65	
66	const jwt = process.env.MARKETIFY_PROBE_JWT;
67	if (!jwt) {
68	  console.error("MARKETIFY_PROBE_JWT must be set for query mode");
69	  process.exit(1);
70	}
71	
72	const rpcRes = await fetch(
73	  `${supabaseUrl}/rest/v1/rpc/list_my_applications`,
74	  {
75	    method: "POST",
76	    headers: {
77	      "Content-Type": "application/json",
78	      Authorization: `Bearer ${jwt}`,
79	      apikey: anonKey,
80	    },
81	    body: "{}",
82	  },
83	);
84	console.log("[rpc list_my_applications]", rpcRes.status);
85	if (rpcRes.status !== 200) {
86	  console.error(await rpcRes.text());
87	  process.exit(2);
88	}
89	
90	type Row = {
91	  id: string;
92	  status:
93	    | "pending"
94	    | "approved"
95	    | "rejected"
96	    | "withdrawn"
97	    | "cancelled_listing_edit"
98	    | "cancelled_listing_closed";
99	  listing_id: string;
100	  listing_title: string | null;
101	  lister_handle: string | null;
102	  version_title: string | null;
103	};
104	const rows = (await rpcRes.json()) as Row[];
105	console.log(`[rpc] ${rows.length} row(s) returned`);
106	for (const r of rows) {
107	  console.log(
108	    `  - ${r.status.padEnd(28)} listing="${r.listing_title}" handle=@${r.lister_handle}`,
109	  );
110	}
111	
112	const bucket = (s: Row["status"]) =>
113	  s === "pending"
114	    ? "pending"
115	    : s === "approved"
116	      ? "approved"
117	      : s === "rejected"
118	        ? "rejected"
119	        : "cancelled";
120	
121	const seen = new Set(rows.map((r) => bucket(r.status)));
122	const required = ["pending", "approved", "rejected", "cancelled"] as const;
123	const missing = required.filter((b) => !seen.has(b));
124	
125	if (missing.length > 0) {
126	  console.error(`[verdict] FAIL — missing buckets: ${missing.join(", ")}`);
127	  process.exit(2);
128	}
129	
130	const handlesPopulated = rows.every((r) => !!r.lister_handle);
131	const titlesPopulated = rows.every((r) => !!r.listing_title || !!r.version_title);
132	if (!handlesPopulated) {
133	  console.error("[verdict] FAIL — lister_handle null on at least one row (silent-null regression)");
134	  process.exit(2);
135	}
136	if (!titlesPopulated) {
137	  console.error("[verdict] FAIL — listing_title and version_title both null on at least one row");
138	  process.exit(2);
139	}
140	
141	console.log(
142	  "[verdict] PASS — all 4 buckets populated, lister_handle + title resolved on every row",
143	);
