1	import { useCallback, useEffect, useMemo, useState } from 'react';
2	import {
3	  Pressable,
4	  SafeAreaView,
5	  ScrollView,
6	  StyleSheet,
7	  Text,
8	  View,
9	  type StyleProp,
10	  type ViewStyle,
11	} from 'react-native';
12	import { router } from 'expo-router';
13	import { StatusPill, type StatusPillStatus } from '@/components/primitives/StatusPill';
14	import { SkeletonCard } from '@/components/primitives/SkeletonCard';
15	import { colors, radii, shadows, spacing } from '@/design/tokens';
16	import { textStyles } from '@/design/typography';
17	import { useAuth } from '@/lib/auth';
18	import { supabase } from '@/lib/supabase';
19	import { formatRelativeTime } from '@/lib/time';
20	import type { Database } from '@/types/supabase';
21	
22	// US-043 — Creator "My Applications" tab. Calls the `list_my_applications`
23	// SECURITY DEFINER RPC which joins applications → listings → users (lister
24	// handle) → listing_versions (snapshot title) under the caller's auth.uid
25	// and returns a flat shape the UI can render directly. The RPC exists
26	// because a plain PostgREST embed would silently null the lister handle
27	// (users RLS is self-only) and the version title for non-active listings
28	// (listing_versions RLS is gated on listing.status='active').
29	//
30	// Segments: Pending / Approved / Rejected / Cancelled per AC.
31	// DB enum has 6 values; withdrawn + cancelled_listing_* all bucket to
32	// "Cancelled" per design §3.1 label + AC's 4-segment design. Route path
33	// matches docs/design.md:151 canonical URL `/(creator)/applications`.
34	
35	type ApplicationStatus = Database['public']['Enums']['application_status'];
36	type Segment = 'pending' | 'approved' | 'rejected' | 'cancelled';
37	type ApplicationRow = Database['public']['Functions']['list_my_applications']['Returns'][number];
38	
39	const STATUS_BUCKET: Record<ApplicationStatus, Segment> = {
40	  pending: 'pending',
41	  approved: 'approved',
42	  rejected: 'rejected',
43	  withdrawn: 'cancelled',
44	  cancelled_listing_edit: 'cancelled',
45	  cancelled_listing_closed: 'cancelled',
46	};
47	
48	const SEGMENTS: readonly { key: Segment; label: string }[] = [
49	  { key: 'pending', label: 'Pending' },
50	  { key: 'approved', label: 'Approved' },
51	  { key: 'rejected', label: 'Rejected' },
52	  { key: 'cancelled', label: 'Cancelled' },
53	];
54	
55	// Segmented control semantics: a11y role "tab" with single-select state.
56	// Chip primitive (checkbox role) is for multi-select filter rows — a
57	// segmented control needs single-select. Keeping this inline rather than
58	// promoting to a shared primitive until another screen needs it.
59	type SegmentControlProps = {
60	  active: Segment;
61	  onChange: (next: Segment) => void;
62	};
63	
64	function SegmentControl({ active, onChange }: SegmentControlProps) {
65	  return (
66	    <View style={styles.segmentRow} accessibilityRole="tablist">
67	      {SEGMENTS.map((s) => (
68	        <SegmentButton
69	          key={s.key}
70	          label={s.label}
71	          selected={active === s.key}
72	          onPress={() => onChange(s.key)}
73	          testID={`segment-${s.key}`}
74	        />
75	      ))}
76	    </View>
77	  );
78	}
79	
80	type SegmentButtonProps = {
81	  label: string;
82	  selected: boolean;
83	  onPress: () => void;
84	  testID?: string;
85	};
86	
87	function SegmentButton({ label, selected, onPress, testID }: SegmentButtonProps) {
88	  const bg = selected ? colors.primarySoft : colors.surface;
89	  const textColor = selected ? colors.primaryDeep : colors.ink;
90	  return (
91	    <Pressable
92	      onPress={onPress}
93	      accessibilityRole="tab"
94	      accessibilityState={{ selected }}
95	      accessibilityLabel={label}
96	      style={[styles.segment, { backgroundColor: bg }, shadows.hard]}
97	      testID={testID}
98	    >
99	      <Text style={[textStyles.micro, { color: textColor }]} allowFontScaling={false}>
100	        {label}
101	      </Text>
102	    </Pressable>
103	  );
104	}
105	
106	export default function Applications() {
107	  const { user } = useAuth();
108	  const userId = user?.id ?? null;
109	
110	  const [segment, setSegment] = useState<Segment>('pending');
111	  const [rows, setRows] = useState<ApplicationRow[]>([]);
112	  const [loading, setLoading] = useState(true);
113	  const [error, setError] = useState<string | null>(null);
114	
115	  const load = useCallback(async () => {
116	    if (!userId) return;
117	    setLoading(true);
118	    setError(null);
119	    const { data, error: rpcError } = await supabase.rpc('list_my_applications');
120	    if (rpcError) {
121	      setError("Couldn't load applications.");
122	      setRows([]);
123	    } else {
124	      setRows(data ?? []);
125	    }
126	    setLoading(false);
127	  }, [userId]);
128	
129	  useEffect(() => {
130	    void load();
131	  }, [load]);
132	
133	  const byBucket = useMemo(() => {
134	    const map: Record<Segment, ApplicationRow[]> = {
135	      pending: [],
136	      approved: [],
137	      rejected: [],
138	      cancelled: [],
139	    };
140	    for (const r of rows) {
141	      map[STATUS_BUCKET[r.status]].push(r);
142	    }
143	    return map;
144	  }, [rows]);
145	
146	  const visible = byBucket[segment];
147	
148	  return (
149	    <SafeAreaView style={styles.root}>
150	      <ScrollView contentContainerStyle={styles.scroll}>
151	        <Text style={[textStyles.display, styles.header]}>Applied</Text>
152	        <SegmentControl active={segment} onChange={setSegment} />
153	
154	        {loading ? (
155	          <View style={styles.list} testID="applications-loading">
156	            <SkeletonCard />
157	            <SkeletonCard />
158	          </View>
159	        ) : error ? (
160	          <View style={styles.emptyBox}>
161	            <Text style={[textStyles.body, { color: colors.danger }]}>{error}</Text>
162	          </View>
163	        ) : visible.length === 0 ? (
164	          <View style={styles.emptyBox} testID={`applications-empty-${segment}`}>
165	            <Text style={[textStyles.body, { color: colors.ink70 }]}>
166	              {emptyMessageFor(segment)}
167	            </Text>
168	          </View>
169	        ) : (
170	          <View style={styles.list}>
171	            {visible.map((row) => (
172	              <ApplicationRowCard key={row.id} row={row} />
173	            ))}
174	          </View>
175	        )}
176	      </ScrollView>
177	    </SafeAreaView>
178	  );
179	}
180	
181	function emptyMessageFor(segment: Segment): string {
182	  switch (segment) {
183	    case 'pending':
184	      return 'No pending applications yet. Apply from Discover.';
185	    case 'approved':
186	      return 'Nothing approved yet — keep applying.';
187	    case 'rejected':
188	      return 'No rejections here.';
189	    case 'cancelled':
190	      return 'No cancelled applications.';
191	  }
192	}
193	
194	type ApplicationRowCardProps = {
195	  row: ApplicationRow;
196	  style?: StyleProp<ViewStyle>;
197	};
198	
199	// Title fallback: prefer listings.title (current), fall back to the
200	// version snapshot title (what the creator originally applied against),
201	// then a generic. Both fields come from the RPC so both are always
202	// populated for rows the caller owns.
203	function resolveTitle(row: ApplicationRow): string {
204	  return row.listing_title || row.version_title || 'Untitled campaign';
205	}
206	
207	function ApplicationRowCard({ row, style }: ApplicationRowCardProps) {
208	  const title = resolveTitle(row);
209	  const handle = row.lister_handle;
210	  const pillStatus: StatusPillStatus = STATUS_BUCKET[row.status];
211	  const relative = formatRelativeTime(new Date(row.created_at));
212	
213	  const onPress = useCallback(() => {
214	    router.push(`/(creator)/listing/${row.listing_id}`);
215	  }, [row.listing_id]);
216	
217	  return (
218	    <Pressable
219	      onPress={onPress}
220	      accessibilityRole="button"
221	      accessibilityLabel={`${title}${handle ? ` by @${handle}` : ''}, ${pillStatus}, applied ${relative}`}
222	      style={[styles.card, shadows.hard, style]}
223	      testID={`application-${row.id}`}
224	    >
225	      <View style={styles.cardTopRow}>
226	        <View style={styles.cardTitleBlock}>
227	          <Text style={[textStyles.h2, { color: colors.ink }]} numberOfLines={2}>
228	            {title}
229	          </Text>
230	          {handle ? (
231	            <Text style={[textStyles.caption, { color: colors.ink70 }]}>@{handle}</Text>
232	          ) : null}
233	        </View>
234	        <StatusPill status={pillStatus} />
235	      </View>
236	      <Text style={[textStyles.caption, { color: colors.ink70 }]}>Applied {relative}</Text>
237	    </Pressable>
238	  );
239	}
240	
241	const styles = StyleSheet.create({
242	  root: { flex: 1, backgroundColor: colors.canvas },
243	  scroll: {
244	    padding: spacing.base,
245	    gap: spacing.md,
246	    paddingBottom: spacing.xxxl,
247	  },
248	  header: {
249	    color: colors.ink,
250	    marginBottom: spacing.xs,
251	  },
252	  segmentRow: {
253	    flexDirection: 'row',
254	    flexWrap: 'wrap',
255	    gap: spacing.sm,
256	    marginBottom: spacing.xs,
257	  },
258	  segment: {
259	    minHeight: 32,
260	    paddingHorizontal: spacing.md,
261	    paddingVertical: spacing.xs + 2,
262	    borderRadius: radii.pill,
263	    borderWidth: 2,
264	    borderColor: colors.ink,
265	    alignItems: 'center',
266	    justifyContent: 'center',
267	  },
268	  list: {
269	    gap: spacing.md,
270	  },
271	  card: {
272	    backgroundColor: colors.surface,
273	    borderColor: colors.ink,
274	    borderWidth: 2,
275	    borderRadius: radii.card,
276	    padding: spacing.base,
277	    gap: spacing.sm,
278	  },
279	  cardTopRow: {
280	    flexDirection: 'row',
281	    gap: spacing.sm,
282	    alignItems: 'flex-start',
283	  },
284	  cardTitleBlock: {
285	    flex: 1,
286	    gap: spacing.xs,
287	  },
288	  emptyBox: {
289	    padding: spacing.lg,
290	    alignItems: 'center',
291	  },
292	});
